INSERT INTO transfer_outgoing VALUES(2,'2026-summer',13,'Arsenal','HIGH','개인 조건 "매우 매우 가깝다"(FootballTransfers 단독) — 5년 계약 준비, 아스날 컨빈스 단계. 이적료 격차 큼: 빌라 £130m 요구 vs 아스날 €85m(반반 분할지급) 제안. [2026-07-09 watch: 개인조건 진전으로 등급 MEDIUM-HIGH→HIGH 상향, 단 이적료 협상은 미해결]','https://www.footballtransfers.com/en/transfer-news/uk-premier-league/2026/07/exclusive-arsenal-very-close-to-morgan-rogers-transfer-breakthrough ; https://www.teamtalk.com/arsenal/morgan-rogers-transfer-news-record-bid-imminent-from-arsenal-villa (2026-07-09)','HIGH — [2026-07-14 재확인] 개인조건 "매우 근접"(원칙적 합의) 진전 보강, 트로사르 베식타스 이적으로 아스날이 로저스 영입을 대체자로 더 적극 추진하는 정황(도미노 효과) 확인. 이적료는 아스날 오프닝 €85m vs 빌라 요구 £130m로 격차 큼. 만잠비 합류로 로저스 매각 명분도 강화(전술 중복). HIGH 유지.');
INSERT INTO transfer_outgoing VALUES(3,'2026-summer',1,'Juventus','HIGH','유벤투스와 개인조건 구두 합의(2029년까지 3년, 연봉 €5.5m — 현재 €7m에서 감액 수용). Fabrizio Romano: 유벤투스 다이렉트 컨택 확인. 이적료 격차: 빌라 최소 €10m 요구 vs 유벤투스 최대 €5m 추가 의향. [2026-07-09 watch: 개인조건 합의로 HIGH 유지·근거 보강, 협상은 월드컵 이후로 지연 전망] [2026-07-14 야간 재확인] 빌라 공식(Damian Vidagany, 365Scores)이 "마르티네스는 잔류, 매각 의사 없음" 공개 부인 — 로마노도 €6-7m 저가설 반박(매각 의향 없다고 재확인). 유벤투스 스포츠디렉터(Carnevali)는 관심만 확인, 최종 합의는 아직. 구두합의 보도와 구단측 부인이 공존하는 상충 국면.','https://www.goal.com/en/lists/emi-martinez-verbally-agrees-juventus-transfer-aston-villa-and-argentina-goalkeeper-prepared-to-reduce-salary/blt15e7adefed63d273 ; https://www.caughtoffside.com/2026/07/08/juventus-direct-contact-emiliano-martinez-fabrizio-romano/ (2026-07-09)','HIGH — [2026-07-14 재확인] 유벤투스 개인조건 합의(연봉 €5.5m, 2029계약)는 유지되나 이적료 보도가 상충 — 디마르지오(€6-7m 근접) vs 로마노(빌라 강경 거부) vs Express&Star(빌라 "매각 협상 의사 자체 없음"). 월드컵 이후로 협상 지연 전망. HIGH 유지, 상충 신호 병기.');
INSERT INTO transfer_outgoing VALUES(5,'2026-summer',16,'Fenerbahçe','MEDIUM-HIGH','왓킨스가 페네르바흐체 계약조건에 서명(구조 합의), 이적료만 남은 상태. 이적료 격차: 페네르바흐체 €25m 제안 vs 빌라 €35m 요구. 클럽간 협상은 월드컵 이후로 예정, 왓킨스는 2028년까지 계약 중.','https://www.astonvillanews.co.uk/transfers/why-aston-villa-are-set-for-ollie-watkins-heartbreak-as-fenerbahce-close-in ; https://uk.sports.yahoo.com/news/why-aston-villa-set-ollie-133854669.html (2026-07-09)','MEDIUM-HIGH — [2026-07-14 재확인] 페네르바흐체측 "3년 계약 합의" 보도 있으나 선수측이 "월드컵 전까지 이적 논의 전면 보류"라며 진화. 이적료 격차도 보도마다 상이(€25-60m). 신호 엇갈려 MEDIUM-HIGH 유지(상향 근거 부족).');
INSERT INTO transfer_outgoing VALUES(6,'2026-summer',3,'Arsenal','MEDIUM-LOW','아스날이 벤 화이트 대체·살리바 백업으로 관심, 빌라는 £50-60m(~€70m) 요구하며 매각 의사 없음(계약 2년 남음). 로저스와 "더블 레이드" 패키지로도 거론.','https://www.footballinsider247.com/aston-villa/transfers/aston-villa-set-ezri-konsa-asking-price-as-arsenal-line-up-deal ; https://thehardtackle.com/transfer-news/2026/07/10/aston-villa-set-to-demand-over-50-million-for-ezri-konsa-amid-arsenal-links/ ; SofaScore/TransferFeed cross-check (2026-07-12)','MEDIUM-LOW — [2026-07-14 재확인] 빌라 내부 소식통 "콘사가 이번 여름 떠나는 걸 못 보겠다"는 회의적 전망 등장, 아스날 자체도 벤 화이트 매각 성사 전까지 자금 확보 불투명. 가격 격차도 여전(£35m 아스날 vs €70m 빌라). MEDIUM에서 하향.');
INSERT INTO transfer_outgoing VALUES(7,'2026-summer',9,'Manchester United','CONFIRMED','벨기에 월드컵 조별탈락 직후 맨유가 급가속. €41m(약 £35m) 바이아웃 조항 발동 임박 — Sky Sports "advanced talks", ESPN 소식통 확인. 본인 올드트래포드 선호 확인(ESPN). 빌라는 오나나 ACL 부상에 이어 두 번째 중원 손실 — 만잠비(LDM, 오늘 실측 추가)로 선제 대응했으나 만잠비는 공격형 성향이라 홀딩/DLP 자원 추가 필요. [갱신 07-14] Romano "HERE WE GO": €41m(£35m) 바이아웃 발동, 개인조건 합의, 메디컬 진행(부킹). [2026-07-14 야간 재확인] 메디컬 부킹(화요일) 보도(The Sun/Luckhurst), INEOS의 에더슨 영입 무산 후 신속 피벗 배경 확인 — CONFIRMED로 상향.','https://www.skysports.com/football/news/11095/13562972/youri-tielemans-manchester-united-in-talks-to-sign-aston-villa-and-belgium-midfielder ; https://www.espn.com/soccer/story/_/id/49348973/youri-tielemans-man-united-advanced-talks-aston-villa-sources ; https://www.footballtransfers.com/en/transfer-news/uk-premier-league/2026/07/man-utd-transfer-news-youri-tielemans-aston-villa-david-ornstein-advanced-talks-summer-2026 (2026-07-13) ; https://www.skysports.com (Plettenberg 메디컬 임박) ; Romano X/YouTube 07-14','CONFIRMED — Romano "here we go" + 메디컬 부킹 보도(복수 소스), 공식 발표만 남음.');
INSERT INTO transfer_outgoing VALUES(8,'2026-summer',5,'Paris Saint-Germain','CONFIRMED','PSG가 누누 멘데스 백업으로 재영입 타진, 이적료 규약상 바이아웃(약 €10m 추정)이 낮아 트리거 가능성. 6도움(PL 최다, 수비수 기준)으로 에메리 체계 핵심이나, 낮은 이적료가 매각 유인. PSG 슈퍼컵(8/12) 상대라는 아이러니. [갱신 07-14] Romano: PSG가 약 €10m 바이아웃 조항 발동, 디뉴 개인합의(누누 멘데스 백업 수용, 3년 계약). [2026-07-14 야간 재확인] 디뉴 본인 파리 복귀 수락 확인(누누 멘데스 백업), 월드컵 이후 바이아웃 발동 시점만 남음 — CONFIRMED로 상향.','https://readastonvilla.com/2026/07/13/aston-villa-face-major-digne-decision-after-psg-clause-emerges/ ; https://www.getfootballnewsfrance.com/2026/psg-express-interest-for-aston-villas-lucas-digne/ ; https://www.teamtalk.com/aston-villa/nightmare-scenario-psg-push-lucas-digne-youri-tielemans-exit (2026-07-13) ; https://www.getfootballnewsfrance.com/2026/psg-to-sign-aston-villas-lucas-digne-after-paying-e10m-release-clause/ (2026-07-14)','CONFIRMED — Romano "here we go"(1티어), 실행 시점만 월드컵 이후로 이연.');
